INSERT INTO categories (id, name, slug, description, parent_id, display_order, is_active, created_at, updated_at) VALUES
(1, 'Sách Kỹ Năng', 'sach-ky-nang', 'Các cuốn sách về phát triển bản thân, kỹ năng sống và làm việc', NULL, 1, TRUE, '2026-02-23 12:08:55', '2026-02-23 12:08:55'),
(2, 'Sách Văn Học', 'sach-van-hoc', 'Các tác phẩm văn học trong và ngoài nước', NULL, 2, TRUE, '2026-02-23 12:08:55', '2026-02-23 12:08:55'),
(3, 'Sách Khoa Học', 'sach-khoa-hoc', 'Sách về khoa học tự nhiên, xã hội và công nghệ', NULL, 3, TRUE, '2026-02-23 12:08:55', '2026-02-23 12:08:55'),
(4, 'Sách Tâm Lý', 'sach-tam-ly', 'Sách về tâm lý học, phát triển cảm xúc và tư duy', NULL, 4, TRUE, '2026-02-23 12:08:55', '2026-02-23 12:08:55'),
(5, 'Sách Kinh Doanh', 'sach-kinh-doanh', 'Sách về kinh tế, quản trị và khởi nghiệp', NULL, 5, TRUE, '2026-02-23 12:08:55', '2026-02-23 12:08:55'),
(6, 'Sách Thiếu Nhi', 'sach-thieu-nhi', 'Sách dành cho trẻ em và thanh thiếu niên', NULL, 6, TRUE, '2026-02-23 12:08:55', '2026-02-23 12:08:55'),
(7, 'Sách Lịch Sử', 'sach-lich-su', 'Sách về lịch sử Việt Nam và thế giới', NULL, 7, TRUE, '2026-02-23 12:08:55', '2026-02-23 12:08:55');
INSERT INTO products (id, title, slug, author, isbn, publisher, publication_year, language, pages, format, description, price, discount_price, stock_quantity, cover_image_url, is_featured, is_bestseller, is_active, view_count, sold_count, rating_count, created_at, updated_at) VALUES
(1, 'Đắc Nhân Tâm', 'dac-nhan-tam', 'Dale Carnegie', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Đắc Nhân Tâm</strong> là cuốn sách kinh điển về nghệ thuật giao tiếp và ứng xử trong cuộc sống. Tác phẩm mang đến những nguyên tắc nền tảng giúp bạn gây thiện cảm, xây dựng mối quan hệ bền vững và tạo ảnh hưởng tích cực đến người khác.<br><br>Thông qua các câu chuyện thực tế và bài học sâu sắc, cuốn sách giúp người đọc hiểu rằng muốn thay đổi người khác trước hết phải thay đổi chính mình. Đây là cẩm nang quan trọng dành cho bất kỳ ai mong muốn thành công trong công việc và cuộc sống.', 108000.00, 85000.00, 100, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014308/imgi_153_image_hclzif.webp', TRUE, TRUE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-24 04:44:01'),
(2, 'Nhà Giả Kim', 'nha-gia-kim', 'Paulo Coelho', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Nhà Giả Kim</strong> kể về hành trình theo đuổi ước mơ của chàng chăn cừu Santiago, người dám rời bỏ vùng an toàn để tìm kiếm kho báu của đời mình.<br><br>Trên hành trình ấy, cậu học được cách lắng nghe trái tim, tin vào những dấu hiệu của cuộc sống và không ngừng tiến bước. Tác phẩm truyền cảm hứng mạnh mẽ cho những ai đang tìm kiếm ý nghĩa và mục tiêu sống.', 79000.00, NULL, 43, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014309/imgi_203_image_huw7so.webp', TRUE, TRUE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-24 07:39:20'),
(3, 'Tuổi Trẻ Đáng Giá Bao Nhiêu', 'tuoi-tre-dang-gia-bao-nhieu', 'Rosie Nguyễn', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Tuổi Trẻ Đáng Giá Bao Nhiêu</strong> là lời chia sẻ chân thành dành cho những người trẻ đang loay hoay giữa những lựa chọn của cuộc đời.<br><br>Cuốn sách khuyến khích bạn đọc nhiều hơn, trải nghiệm nhiều hơn và dám bước ra khỏi vùng an toàn để khám phá thế giới. Đây là hành trang tinh thần giúp tuổi trẻ trở nên ý nghĩa và không bị lãng phí.', 80000.00, 68000.00, 60, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014882/imgi_4_image_wgujq4.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:29:54'),
(4, 'Sapiens: Lược Sử Loài Người', 'sapiens-luoc-su-loai-nguoi', 'Yuval Noah Harari', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Sapiens: Lược Sử Loài Người</strong> mang đến cái nhìn toàn diện về lịch sử phát triển của nhân loại từ thời tiền sử đến hiện đại.<br><br>Tác giả phân tích những cuộc cách mạng lớn đã định hình xã hội, kinh tế và niềm tin của con người, giúp người đọc hiểu sâu sắc hơn về nguồn gốc và vị trí của mình trong thế giới ngày nay.', 189000.00, NULL, 27, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014308/imgi_167_image_hctqqz.webp', TRUE, TRUE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-24 07:39:20'),
(5, 'Atomic Habits', 'atomic-habits', 'James Clear', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Atomic Habits</strong> là hướng dẫn thực tế về cách xây dựng thói quen tốt và loại bỏ thói quen xấu thông qua những thay đổi nhỏ nhưng bền vững.<br><br>Cuốn sách nhấn mạnh sức mạnh của việc cải thiện 1% mỗi ngày và xây dựng hệ thống thay vì chỉ tập trung vào mục tiêu, giúp bạn tạo ra những thay đổi lâu dài trong cuộc sống.', 150000.00, 125000.00, 40, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1769498046/imgi_48_image_npxavm.webp', TRUE, TRUE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:30:29'),
(6, 'Tâm Lý Học Tội Phạm', 'tam-ly-hoc-toi-pham', 'Diệp Lạc Vô Tâm', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Tâm Lý Học Tội Phạm</strong> khám phá thế giới tâm lý phức tạp đằng sau hành vi phạm tội của con người.<br><br>Cuốn sách giúp người đọc hiểu rõ động cơ, hoàn cảnh và yếu tố tâm lý dẫn đến các hành vi sai lệch, từ đó mở rộng góc nhìn về bản chất con người và xã hội.', 95000.00, NULL, 25, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014882/imgi_258_image_kf626u.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:30:39'),
(7, 'Nghệ Thuật Bán Hàng', 'nghe-thuat-ban-hang', 'Brian Tracy', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Nghệ Thuật Bán Hàng</strong> cung cấp những chiến lược và kỹ năng cần thiết để trở thành một người bán hàng chuyên nghiệp.<br><br>Tác phẩm tập trung vào việc xây dựng niềm tin, thấu hiểu khách hàng và tạo giá trị thực sự, giúp bạn nâng cao doanh số và phát triển sự nghiệp kinh doanh bền vững.', 130000.00, 110000.00, 35, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1769498046/imgi_42_image_p5kpvc.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:30:47'),
(8, 'Thinking, Fast and Slow', 'thinking-fast-and-slow', 'Daniel Kahneman', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Thinking, Fast and Slow</strong> phân tích hai hệ thống tư duy chi phối cách con người đưa ra quyết định.<br><br>Cuốn sách giúp bạn nhận diện những sai lầm nhận thức thường gặp và hiểu rõ hơn về cách bộ não vận hành, từ đó cải thiện khả năng suy nghĩ và ra quyết định trong cuộc sống.', 200000.00, 165000.00, 20, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014308/imgi_324_image_kqwfo7.webp', TRUE, TRUE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:30:49'),
(9, 'Cà Phê Cùng Tony', 'ca-phe-cung-tony', 'Tony Buổi Sáng', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Cà Phê Cùng Tony</strong> tập hợp những câu chuyện đời thường nhưng đầy sâu sắc về cách sống, học tập và làm việc.<br><br>Với lối viết hài hước nhưng thẳng thắn, cuốn sách mang đến nhiều bài học thực tế giúp người trẻ định hướng bản thân và phát triển tư duy tích cực.', 72000.00, NULL, 55, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014308/imgi_157_image_uqweqv.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:30:57'),
(10, 'Homo Deus: Lược Sử Tương Lai', 'homo-deus-luoc-su-tuong-lai', 'Yuval Noah Harari', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Homo Deus: Lược Sử Tương Lai</strong> đưa ra những dự đoán táo bạo về tương lai của nhân loại trong thời đại công nghệ và trí tuệ nhân tạo.<br><br>Cuốn sách đặt ra những câu hỏi lớn về đạo đức, tôn giáo và vai trò của con người khi khoa học ngày càng phát triển mạnh mẽ.', 195000.00, NULL, 28, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014308/imgi_137_image_jeryl1.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:05'),
(11, 'Đời Ngắn Đừng Ngủ Dài', 'doi-ngan-dung-ngu-dai', 'Robin Sharma', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Đời Ngắn Đừng Ngủ Dài</strong> truyền tải thông điệp sống tích cực và không trì hoãn ước mơ của mình.<br><br>Tác phẩm khuyến khích bạn tận dụng từng ngày để học hỏi, phát triển bản thân và sống trọn vẹn thay vì để thời gian trôi qua vô nghĩa.', 110000.00, 88000.00, 42, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014308/imgi_121_image_x4chnx.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:07'),
(12, 'Mắt Biếc', 'mat-biec', 'Nguyễn Nhật Ánh', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Mắt Biếc</strong> là câu chuyện tình yêu trong sáng nhưng đầy day dứt của tuổi học trò.<br><br>Tác phẩm khắc họa ký ức tuổi thơ và những rung động đầu đời, mang đến cho người đọc cảm xúc nhẹ nhàng nhưng sâu lắng.', 95000.00, NULL, 70, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014309/imgi_15_image_guc2py.webp', TRUE, TRUE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:11'),
(13, 'Chiến Tranh Tiền Tệ', 'chien-tranh-tien-te', 'Song Hồng Băng', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Chiến Tranh Tiền Tệ</strong> phân tích những cuộc đấu tranh tài chính ngầm giữa các cường quốc trên thế giới.<br><br>Cuốn sách giúp người đọc hiểu rõ hơn về hệ thống tiền tệ toàn cầu và những ảnh hưởng sâu rộng của nó đến kinh tế và chính trị.', 180000.00, 158000.00, 18, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014309/imgi_225_image_f4ki83.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:17'),
(14, 'Dế Mèn Phiêu Lưu Ký', 'de-men-phieu-luu-ky', 'Tô Hoài', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Dế Mèn Phiêu Lưu Ký</strong> là tác phẩm thiếu nhi kinh điển kể về hành trình trưởng thành của chú Dế Mèn.<br><br>Thông qua những chuyến phiêu lưu, câu chuyện gửi gắm bài học về tình bạn, lòng dũng cảm và trách nhiệm với cộng đồng.', 45000.00, NULL, 80, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014309/imgi_207_image_xkliye.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:19'),
(15, 'Lược Sử Thời Gian', 'luoc-su-thoi-gian', 'Stephen Hawking', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Lược Sử Thời Gian</strong> đưa người đọc khám phá những bí ẩn của vũ trụ như hố đen, không gian và thời gian.<br><br>Với cách diễn đạt dễ hiểu, cuốn sách giúp khoa học trở nên gần gũi hơn với đại chúng.', 170000.00, 145000.00, 22, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014310/imgi_261_image_v6tlng.webp', TRUE, TRUE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:26'),
(16, 'Tôi Thấy Hoa Vàng Trên Cỏ Xanh', 'toi-thay-hoa-vang-tren-co-xanh', 'Nguyễn Nhật Ánh', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Tôi Thấy Hoa Vàng Trên Cỏ Xanh</strong> tái hiện tuổi thơ miền quê Việt Nam đầy thơ mộng và trong trẻo.<br><br>Câu chuyện mang đến những cảm xúc ấm áp về tình anh em, tình bạn và những ký ức không thể quên.', 98000.00, NULL, 65, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014309/imgi_216_image_h5l8zm.webp', TRUE, TRUE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:32'),
(17, 'Tâm Lý Học Về Tiền', 'tam-ly-hoc-ve-tien', 'Morgan Housel', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Tâm Lý Học Về Tiền</strong> giúp người đọc hiểu rằng thành công tài chính không chỉ phụ thuộc vào kiến thức mà còn vào hành vi và tư duy.<br><br>Cuốn sách phân tích những sai lầm phổ biến trong quản lý tiền bạc và đưa ra góc nhìn thực tế về đầu tư và tiết kiệm.', 160000.00, 135000.00, 32, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014309/imgi_180_image_clvj2d.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:35'),
(18, 'Lịch Sử Việt Nam Bằng Tranh', 'lich-su-viet-nam-bang-tranh', 'Trần Bạch Đằng', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Lịch Sử Việt Nam Bằng Tranh</strong> tái hiện các giai đoạn quan trọng của lịch sử dân tộc thông qua hình ảnh minh họa sinh động.<br><br>Tác phẩm giúp người đọc, đặc biệt là giới trẻ, tiếp cận lịch sử một cách trực quan và dễ hiểu hơn.', 225000.00, NULL, 15, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014309/imgi_240_image_mdr6j1.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:42'),
(19, '7 Thói Quen Hiệu Quả', '7-thoi-quen-hieu-qua', 'Stephen Covey', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>7 Thói Quen Hiệu Quả</strong> giới thiệu những nguyên tắc giúp phát triển cá nhân và nâng cao hiệu suất làm việc.<br><br>Cuốn sách tập trung vào việc xây dựng tư duy chủ động, quản lý thời gian và phát triển mối quan hệ hiệu quả.', 140000.00, 115000.00, 38, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1770014309/imgi_191_image_twinzm.webp', TRUE, TRUE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:44'),
(20, 'Đắc Nhân Tâm Dành Cho Tuổi Teen', 'dac-nhan-tam-danh-cho-tuoi-teen', 'Dale Carnegie', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', '<strong>Đắc Nhân Tâm Dành Cho Tuổi Teen</strong> là phiên bản được điều chỉnh phù hợp với lứa tuổi thanh thiếu niên.<br><br>Cuốn sách giúp các bạn trẻ xây dựng sự tự tin, kỹ năng giao tiếp và khả năng ứng xử tích cực trong môi trường học đường và gia đình.', 95000.00, 78000.00, 48, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1769498046/imgi_23_image_zpdstc.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-23 12:08:55', '2026-02-23 12:31:48'),
(21, 'Người Đua Diều', 'nguoi-dua-dieu', 'Khaled Hosseini', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', 'Người Đua Diều của Khaled Hosseini là một tiểu thuyết giàu cảm xúc, phản ánh hành trình trưởng thành nội tâm của con người trong bối cảnh Afghanistan nhiều biến động. Cuốn sách xoay quanh những mối quan hệ gắn bó nhưng đầy chênh lệch, những lựa chọn mang tính đạo đức và cách quá khứ âm thầm định hình con người ở hiện tại.', 65000.00, 45000.00, 11, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1771917175/image_gjgjhm.webp', TRUE, TRUE, TRUE, 0, 0, 0, '2026-02-24 07:13:00', '2026-02-24 07:13:49'),
(22, 'Mưu Hèn Kế Bẩn Nơi Công Sở', 'muu-hen-ke-ban-noi-cong-so', 'Mike Phipps', NULL, NULL, NULL, 'Vietnamese', NULL, 'Paperback', 'Ở môi trường công sở, có thể bắt gặp vô vàn chiêu thức, mưu kế để "hạ bệ" đồng nghiệp, ngay cả khi đó từng là những đồng nghiệp rất thân thiết với nhau. Vậy bạn phải làm sao để vừa đối phó với tiểu nhân nơi công sở, lại vừa hoàn thành tốt công việc được giao phó?', 10000.00, NULL, 100, 'https://res.cloudinary.com/djuksxdrw/image/upload/v1771917277/image_1_vm5oga.webp', FALSE, FALSE, TRUE, 0, 0, 0, '2026-02-24 07:15:41', '2026-02-24 07:23:12');
